import{_ as a,c as e,o as i,a5 as l}from"./chunks/framework.DxlQWoOq.js";const _=JSON.parse('{"title":"隐私权政策","description":"","frontmatter":{"aside":false},"headers":[],"relativePath":"privacy-policy.md","filePath":"privacy-policy.md","lastUpdated":null}'),o={name:"privacy-policy.md"},r=l('<h1 id="隐私权政策" tabindex="-1">隐私权政策 <a class="header-anchor" href="#隐私权政策" aria-label="Permalink to &quot;隐私权政策&quot;">​</a></h1><p>目录表</p><nav class="table-of-contents"><ul><li><a href="#引言">引言</a></li><li><a href="#适用法规遵从">适用法规遵从</a></li><li><a href="#数据收集与使用">数据收集与使用</a></li><li><a href="#数据共享">数据共享</a></li><li><a href="#用户权利">用户权利</a></li><li><a href="#数据保留">数据保留</a></li><li><a href="#安全事件通知">安全事件通知</a></li><li><a href="#cookie-与追踪技术">Cookie 与追踪技术</a></li><li><a href="#政策更新">政策更新</a></li><li><a href="#联系方式">联系方式</a></li></ul></nav><h2 id="引言" tabindex="-1">引言 <a class="header-anchor" href="#引言" aria-label="Permalink to &quot;引言&quot;">​</a></h2><p>感谢您选择使用<strong>一个朋友</strong>（以下简称“我们”）的服务。我们深知隐私对您极为重要，因此制定了本隐私权政策，以确保您了解我们如何收集、使用、共享以及保护您的个人信息。同时，我们也希望您充分了解自己在控制个人信息方面的权利。</p><h2 id="适用法规遵从" tabindex="-1">适用法规遵从 <a class="header-anchor" href="#适用法规遵从" aria-label="Permalink to &quot;适用法规遵从&quot;">​</a></h2><p>我们承认并尊重所有适用的数据保护法律和隐私法规，包括但不限于欧盟通用数据保护条例（GDPR）、加州隐私权法案（CPRA）及其它地方性隐私法律。</p><h2 id="数据收集与使用" tabindex="-1">数据收集与使用 <a class="header-anchor" href="#数据收集与使用" aria-label="Permalink to &quot;数据收集与使用&quot;">​</a></h2><ol><li>个性化广告。我们收集有限的数据用于提供个性化广告，数据包括但不仅限于您的设备类型、非精确位置、您使用的网站或应用以及广告互动历史。</li><li>广告效果分析。我们衡量您对广告的反应（是否查看或点击广告，广告是否促使您采取行动等）以评估广告的效果性。</li><li>内容效果分析。我们评估您如何与内容互动，帮助我们确定内容如何满足您的兴趣，并确保准确投放。</li><li>受众分析。我们可能结合多种数据源来分析用户群体，以改善我们对受众特征的理解，并针对性地提供广告和内容。</li><li>服务改进。我们使用您的互动信息来持续优化我们的产品和服务，并开发新功能。</li></ol><h2 id="数据共享" tabindex="-1">数据共享 <a class="header-anchor" href="#数据共享" aria-label="Permalink to &quot;数据共享&quot;">​</a></h2><p>我们承诺保护您的个人信息，不会与外界共享您的个人标识信息，除非:</p><ul><li>您给予我们明确的同意；</li><li>法律要求；</li><li>在合并、收购或资产出售的情况下，我们将在可能的情况下通知您，并确保接收方遵守本隐私权政策。</li></ul><h2 id="用户权利" tabindex="-1">用户权利 <a class="header-anchor" href="#用户权利" aria-label="Permalink to &quot;用户权利&quot;">​</a></h2><p>您拥有诸多权利，包括访问、更正或删除您的个人信息，以及在某些情况下限制或反对我们处理您的数据。如果您希望行使这些权利，请联系我们。</p><h2 id="数据保留" tabindex="-1">数据保留 <a class="header-anchor" href="#数据保留" aria-label="Permalink to &quot;数据保留&quot;">​</a></h2><p>我们只会在必要时期内保留您的个人信息以满足收集目的，并将在不再需要时妥善删除。</p><h2 id="安全事件通知" tabindex="-1">安全事件通知 <a class="header-anchor" href="#安全事件通知" aria-label="Permalink to &quot;安全事件通知&quot;">​</a></h2><p>在不幸发生数据泄露事件时，我们将依照法律规定和企业政策，及时通知您并采取一切必要措施以限制损害。</p><h2 id="cookie-与追踪技术" tabindex="-1">Cookie 与追踪技术 <a class="header-anchor" href="#cookie-与追踪技术" aria-label="Permalink to &quot;Cookie 与追踪技术&quot;">​</a></h2><p>我们可能使用 Cookie 和类似追踪技术来改善您的使用体验并收集有关您使用习惯的信息。</p><h2 id="政策更新" tabindex="-1">政策更新 <a class="header-anchor" href="#政策更新" aria-label="Permalink to &quot;政策更新&quot;">​</a></h2><p>本隐私政策可能不时更新，以反映我们服务的变化以及客户反馈。我们鼓励您定期审核此页了解最新的隐私信息。</p><h2 id="联系方式" tabindex="-1">联系方式 <a class="header-anchor" href="#联系方式" aria-label="Permalink to &quot;联系方式&quot;">​</a></h2><p>对于本政策或您的个人信息有任何疑问，请<a href="/contact.html">联系我们</a>。</p><p>我们将努力保护您的隐私，并感谢您对我们的信任和选择。我们致力于不断提升服务与保护，以确保您的个人信息安全。</p>',25),t=[r];function h(n,c,s,d,p,f){return i(),e("div",null,t)}const b=a(o,[["render",h]]);export{_ as __pageData,b as default};
